     1→/**
     2→ * Completion-time social action verification.
     3→ * Confirms user actually performed the task (follow, like, repost, post, join, etc.)
     4→ * Separate from social-validator.ts which only checks target existence at creation time.
     5→ */
     6→import { PrismaClient } from '@prisma/client'
     7→import { extractTweetId, normaliseHandle } from '../x/x-utils'
     8→import { getTweetInfo, checkRetweet, checkFollow } from '../x/x-twitter-api45-client'
     9→import { getGuildMember, getUserGuildMember, resolveInvite } from '../discord/discord-rest-client'
    10→import { validateSocialTarget, type SocialValidationResult } from './social-validator'
    11→
    12→export interface VerificationContext {
    13→  userId: string
    14→  prisma: PrismaClient
    15→  // X identity
    16→  xId?: string | null
    17→  xHandle?: string | null
    18→  xAccessToken?: string | null
    19→  xRefreshToken?: string | null
    20→  xTokenExpiry?: Date | null
    21→  // Discord identity
    22→  discordId?: string | null
    23→  discordAccessToken?: string | null
    24→  // Telegram identity
    25→  telegramId?: string | null
    26→  // Proof URLs for post/quote_post (map of taskIndex → URL)
    27→  proofUrls?: Record<number, string>
    28→  // Task params from quest definition
    29→  params?: Record<string, string>
    30→  // Telegram bot token
    31→  telegramBotToken?: string
    32→}
    33→
    34→// ── X Verification ──────────────────────────────────────────────
    35→
    36→async function verifyXAction(
    37→  actionType: string, ctx: VerificationContext, taskIndex: number,
    38→): Promise<SocialValidationResult> {
    39→  // Support multiple param key conventions used by quest creators
    40→  const targetValue = ctx.params?.targetUrl || ctx.params?.postUrl || ctx.params?.accountHandle || ctx.params?.username || ''
    41→
    42→  switch (actionType) {
    43→    case 'post':
    44→    case 'quote_post': {
    45→      const proofUrl = ctx.proofUrls?.[taskIndex]
    46→      if (!proofUrl) return { valid: false, error: 'Paste your tweet URL to verify' }
    47→      const proofTweetId = extractTweetId(proofUrl)
    48→      if (!proofTweetId) return { valid: false, error: 'Invalid tweet URL — use format: https://x.com/.../status/...' }
    49→      if (!ctx.xHandle) return { valid: false, error: 'Link your X account to verify this task' }
    50→
    51→      const tweet = await getTweetInfo(proofTweetId)
    52→      if (!tweet) return { valid: false, error: 'Tweet not found — is it public?' }
    53→
    54→      if (normaliseHandle(tweet.authorScreenName) !== normaliseHandle(ctx.xHandle)) {
    55→        return { valid: false, error: 'This tweet was not posted by your linked X account' }
    56→      }
    57→
    58→      if (actionType === 'quote_post') {
    59→        const targetTweetId = extractTweetId(targetValue)
    60→        if (targetTweetId) {
    61→          const quoteOk =
    62→            tweet.quotedTweetId === targetTweetId ||
    63→            tweet.entityUrls.some(u => u.includes(targetTweetId)) ||
    64→            tweet.text.includes(targetTweetId)
    65→          if (!quoteOk) return { valid: false, error: 'This tweet does not quote the required post' }
    66→        }
    67→      }
    68→      return { valid: true }
    69→    }
    70→
    71→    case 'follow_account': {
    72→      if (!ctx.xHandle) return { valid: false, error: 'Link your X account to verify this task' }
    73→      const targetHandle = targetValue.replace(/^@/, '').replace(/^https?:\/\/(x|twitter)\.com\//, '').split('/')[0]
    74→      if (!targetHandle) return { valid: false, error: 'Quest task missing target account — contact quest creator' }
    75→
    76→      const follows = await checkFollow(ctx.xHandle, targetHandle)
    77→      if (follows === null) return { valid: false, error: 'Follow verification unavailable — try again later' }
    78→      return follows ? { valid: true } : { valid: false, error: 'not following this account' }
    79→    }
    80→
    81→    case 'repost': {
    82→      if (!ctx.xHandle) return { valid: false, error: 'Link your X account to verify this task' }
    83→      const tweetId = extractTweetId(targetValue) || targetValue
    84→      if (!tweetId) return { valid: false, error: 'Quest task missing tweet URL — contact quest creator' }
    85→
    86→      const retweeted = await checkRetweet(ctx.xHandle, tweetId)
    87→      if (retweeted === null) return { valid: false, error: 'Repost verification unavailable — try again later' }
    88→      return retweeted ? { valid: true } : { valid: false, error: 'You have not reposted this tweet' }
    89→    }
    90→
    91→    case 'like_post':
    92→      // Like verification not supported via this API — auto-pass
    93→      return { valid: true }
    94→
    95→    default:
    96→      return { valid: true }
    97→  }
    98→}
    99→
   100→// ── Discord Verification ────────────────────────────────────────
   101→
   102→async function verifyDiscordAction(
   103→  actionType: string, ctx: VerificationContext,
   104→): Promise<SocialValidationResult> {
   105→  if (!ctx.discordId) return { valid: false, error: 'Link your Discord account to verify this task' }
   106→
   107→  if (actionType === 'join_server') {
   108→    let guildId = ctx.params?.guildId
   109→    // Fallback: resolve inviteUrl → guildId (handles legacy quests or when createQuest/updateQuest did not resolve)
   110→    if (!guildId && ctx.params?.inviteUrl) {
   111→      const code = ctx.params.inviteUrl.replace(/^https?:\/\/(discord\.gg|discord\.com\/invite)\//i, '').trim()
   112→      if (code) {
   113→        const guild = await resolveInvite(code)
   114→        if (guild) guildId = guild.guildId
   115→      }
   116→    }
   117→    if (!guildId) return { valid: false, error: 'Quest task missing guildId — contact quest creator' }
   118→
   119→    // Prefer OAuth user token (no bot needed)
   120→    if (ctx.discordAccessToken) {
   121→      const roles = await getUserGuildMember(ctx.discordAccessToken, guildId)
   122→      if (roles !== null) return { valid: true }
   123→    }
   124→    // Fallback to bot
   125→    const botRoles = await getGuildMember(guildId, ctx.discordId)
   126→    if (botRoles !== null) return { valid: true }
   127→
   128→    return { valid: false, error: 'You have not joined this Discord server' }
   129→  }
   130→
   131→  // verify_role: delegate to existing validateDiscordRole via validateSocialTarget
   132→  if (actionType === 'verify_role') {
   133→    return validateSocialTarget('discord', 'verify_role', '', undefined, {
   134→      discordId: ctx.discordId,
   135→      discordAccessToken: ctx.discordAccessToken,
   136→      params: ctx.params,
   137→    })
   138→  }
   139→
   140→  return { valid: true }
   141→}
   142→
   143→// ── Telegram Verification ───────────────────────────────────────
   144→
   145→async function verifyTelegramAction(
   146→  actionType: string, ctx: VerificationContext,
   147→): Promise<SocialValidationResult> {
   148→  if (actionType !== 'join_channel') return { valid: true }
   149→  if (!ctx.telegramId) return { valid: false, error: 'Link your Telegram account to verify this task' }
   150→  if (!ctx.telegramBotToken) return { valid: false, error: 'Telegram verification unavailable' }
   151→
   152→  const channelUrl = ctx.params?.channelUrl || ctx.params?.targetUrl || ''
   153→  let chatId: string
   154→  const urlMatch = channelUrl.match(/t\.me\/([A-Za-z0-9_]+)/)
   155→  if (urlMatch) chatId = `@${urlMatch[1]}`
   156→  else if (channelUrl.startsWith('@')) chatId = channelUrl
   157→  else chatId = `@${channelUrl.replace(/^https?:\/\//, '')}`
   158→
   159→  try {
   160→    const res = await fetch(
   161→      `https://api.telegram.org/bot${ctx.telegramBotToken}/getChatMember?chat_id=${encodeURIComponent(chatId)}&user_id=${ctx.telegramId}`,
   162→      { signal: AbortSignal.timeout(8000) },
   163→    )
   164→
   165→    // Always parse body — Telegram always returns JSON even for HTTP errors
   166→    const data = await res.json() as { ok: boolean; result?: { status: string }; description?: string; error_code?: number }
   167→
   168→    if (!data.ok) {
   169→      const desc = data.description ?? ''
   170→      console.error(`[Telegram] getChatMember failed for chatId=${chatId} userId=${ctx.telegramId}: ${res.status} ${desc}`)
   171→
   172→      if (desc.includes('CHAT_ADMIN_REQUIRED') || res.status === 403)
   173→        return { valid: false, error: 'Bot must be added as an admin of this channel' }
   174→      if (desc.includes('chat not found'))
   175→        return { valid: false, error: 'Channel not found — verify the channel URL in the quest task' }
   176→      if (desc.includes('USER_ID_INVALID') || desc.includes('user not found'))
   177→        return { valid: false, error: 'Could not verify your Telegram account — try unlinking and relinking' }
   178→
   179→      return { valid: false, error: `Telegram error: ${desc || 'Could not check membership'}` }
   180→    }
   181→
   182→    const joined = ['creator', 'administrator', 'member', 'restricted'].includes(data.result?.status ?? '')
   183→    return joined
   184→      ? { valid: true }
   185→      : { valid: false, error: 'You have not joined this channel' }
   186→  } catch {
   187→    return { valid: false, error: 'Telegram API unavailable — try again later' }
   188→  }
   189→}
   190→
   191→// ── Main Dispatcher ─────────────────────────────────────────────
   192→
   193→/** Completion-time verification: did user actually perform this action? */
   194→export async function verifySocialAction(
   195→  platform: string, actionType: string, taskIndex: number, ctx: VerificationContext,
   196→): Promise<SocialValidationResult> {
   197→  switch (platform) {
   198→    case 'x': return verifyXAction(actionType, ctx, taskIndex)
   199→    case 'discord': return verifyDiscordAction(actionType, ctx)
   200→    case 'telegram': return verifyTelegramAction(actionType, ctx)
   201→    default: return { valid: true }
   202→  }
   203→}
