     1→import { randomBytes, randomUUID } from 'crypto';
     2→import { PrismaClient } from '@prisma/client';
     3→import type { QuestTask } from '@clawquest/shared';
     4→import { REWARD_TYPE } from '@clawquest/shared';
     5→
     6→const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
     7→const QUEST_TASK_ACTION_TYPES = [
     8→    'follow_account', 'like_post', 'repost', 'post', 'quote_post',
     9→    'join_server', 'verify_role', 'join_channel',
    10→] as const;
    11→const QUEST_TASK_PLATFORMS = ['x', 'discord', 'telegram'] as const;
    12→
    13→/** Normalize raw tasks from DB (legacy or partial shape) to QuestTaskSchema shape for response. */
    14→function normalizeQuestTasks(raw: unknown): QuestTask[] {
    15→    if (!Array.isArray(raw)) return [];
    16→    return raw.map((t: any) => {
    17→        const id = typeof t?.id === 'string' && UUID_RE.test(t.id) ? t.id : randomUUID();
    18→        const platform = t?.platform && QUEST_TASK_PLATFORMS.includes(t.platform) ? t.platform : 'x';
    19→        const actionType = t?.actionType && QUEST_TASK_ACTION_TYPES.includes(t.actionType) ? t.actionType : 'follow_account';
    20→        const label = typeof t?.label === 'string' && t.label.length > 0 ? t.label.slice(0, 100) : 'Task';
    21→        const params = t?.params && typeof t.params === 'object' && !Array.isArray(t.params)
    22→            ? Object.fromEntries(Object.entries(t.params).filter(([, v]) => typeof v === 'string').map(([k, v]) => [String(k), v as string]))
    23→            : {};
    24→        const requireTagFriends = typeof t?.requireTagFriends === 'boolean' ? t.requireTagFriends : false;
    25→        return { id, platform, actionType, label, params, requireTagFriends };
    26→    });
    27→}
    28→import { resolveInvite } from '../discord/discord-rest-client';
    29→import { validatePublishRequirements } from './quests.publish-validator';
    30→
    31→// ─── Regex patterns for task param validation ────────────────────────────────
    32→export const X_POST_URL_RE = /^https?:\/\/(x\.com|twitter\.com)\/\w+\/status\/\d+/i;
    33→export const X_USERNAME_RE = /^@?[\w]{1,15}$/;
    34→export const DISCORD_INVITE_RE = /^https?:\/\/(discord\.gg|discord\.com\/invite)\/[\w-]+$/i;
    35→export const TELEGRAM_CHANNEL_RE = /^(@[\w]{5,32}|https?:\/\/t\.me\/[\w]+)$/i;
    36→
    37→/** Validate task params based on platform + actionType. Returns error string or null. */
    38→export function validateTaskParams(task: QuestTask): string | null {
    39→    const p = task.params;
    40→    switch (task.actionType) {
    41→        case 'follow_account':
    42→            if (!p.username || !X_USERNAME_RE.test(p.username))
    43→                return `Task "${task.label}": invalid X username "${p.username || ''}"`;
    44→            break;
    45→        case 'like_post':
    46→        case 'repost':
    47→        case 'quote_post':
    48→            if (!p.postUrl || !X_POST_URL_RE.test(p.postUrl))
    49→                return `Task "${task.label}": invalid X post URL "${p.postUrl || ''}"`;
    50→            break;
    51→        case 'post':
    52→            if (!p.content || p.content.length > 280)
    53→                return `Task "${task.label}": post content required (max 280 chars)`;
    54→            break;
    55→        case 'join_server':
    56→            if (!p.inviteUrl || !DISCORD_INVITE_RE.test(p.inviteUrl))
    57→                return `Task "${task.label}": invalid Discord invite URL "${p.inviteUrl || ''}"`;
    58→            break;
    59→        case 'verify_role':
    60→            if (!p.inviteUrl || !DISCORD_INVITE_RE.test(p.inviteUrl))
    61→                return `Task "${task.label}": invalid Discord invite URL "${p.inviteUrl || ''}"`;
    62→            if (!p.roleId)
    63→                return `Task "${task.label}": role ID is required`;
    64→            if (!p.roleName)
    65→                return `Task "${task.label}": role name is required`;
    66→            break;
    67→        case 'join_channel':
    68→            if (!p.channelUrl || !TELEGRAM_CHANNEL_RE.test(p.channelUrl))
    69→                return `Task "${task.label}": invalid Telegram channel "${p.channelUrl || ''}"`;
    70→            break;
    71→        default:
    72→            return `Task "${task.label}": unknown action type "${task.actionType}"`;
    73→    }
    74→    return null;
    75→}
    76→
    77→/** Validate all tasks in an array. Returns first error or null. */
    78→export function validateAllTasks(tasks: QuestTask[]): string | null {
    79→    for (const task of tasks) {
    80→        const err = validateTaskParams(task);
    81→        if (err) return err;
    82→    }
    83→    return null;
    84→}
