    86→// ─── Token generators ─────────────────────────────────────────────────────────
    87→
    88→export function generateClaimToken(): string {
    89→    return 'quest_' + randomBytes(32).toString('hex');
    90→}
    91→
    92→export function generatePreviewToken(): string {
    93→    return 'pv_' + randomBytes(24).toString('hex');
    94→}
    95→
    96→export function generateCollabToken(): string {
    97→    return 'collab_' + randomBytes(32).toString('hex');
    98→}
