   129→// ─── Quest creation ───────────────────────────────────────────────────────────
   130→
   131→export interface CreateQuestInput {
   132→    title: string;
   133→    description: string;
   134→    sponsor?: string;
   135→    type?: string;
   136→    status?: string;
   137→    rewardAmount: number;
   138→    rewardType?: string;
   139→    totalSlots?: number;
   140→    tags?: string[];
   141→    requiredSkills?: string[];
   142→    requireVerified?: boolean;
   143→    tasks?: QuestTask[];
   144→    expiresAt?: string;
   145→    startAt?: string;
   146→    network?: string;
   147→    drawTime?: string;
   148→    fundingMethod?: 'crypto' | 'stripe';
   149→    llmKeyRewardEnabled?: boolean;
   150→    llmKeyTokenLimit?: number;
   151→    creatorTelegramId?: bigint;
   152→    // LLM Model Reward (LLMTOKEN_OPENROUTER)
   153→    llmModelId?: string;
   154→    tokenBudgetPerWinner?: number;
   155→}
   156→
   157→export interface QuestCreator {
   158→    agentId?: string;   // set when agent creates via API
   159→    userId?: string;    // set when human creates via dashboard
   160→    email?: string;     // human email
   161→}
   162→
   163→export async function createQuest(
   164→    prisma: PrismaClient,
   165→    input: CreateQuestInput,
   166→    creator?: QuestCreator,
   167→) {
   168→    const tasks: QuestTask[] = input.tasks ?? [];
   169→
   170→    // Auto-resolve Discord invite → guildId for join_server tasks missing guildId
   171→    for (const task of tasks) {
   172→        if (task.actionType === 'join_server' && task.params?.inviteUrl && !task.params.guildId) {
   173→            const code = task.params.inviteUrl.replace(/^https?:\/\/(discord\.gg|discord\.com\/invite)\//, '');
   174→            const guild = await resolveInvite(code);
   175→            if (guild) {
   176→                task.params.guildId = guild.guildId;
   177→            }
   178→        }
   179→    }
   180→
   181→    // Validate publish requirements for non-draft quests (agent flow creates with status='live')
   182→    if (input.status !== 'draft') {
   183→        const taskErr = validateAllTasks(tasks);
   184→        if (taskErr) throw new QuestValidationError(taskErr);
   185→
   186→        // Build a quest-like object for publish validation
   187→        const { validatePublishRequirements } = await import('./quests.publish-validator');
   188→        const publishErr = validatePublishRequirements({
   189→            ...input,
   190→            tasks,
   191→            fundingStatus: input.rewardType === 'LLM_KEY' ? 'confirmed' : 'pending',
   192→            totalFunded: 0,
   193→        });
   194→        if (publishErr) {
   195→            const messages = Object.values(publishErr.fields).join('; ');
   196→            throw new QuestValidationError(`Cannot publish: ${messages}`);
   197→        }
   198→    }
   199→
   200→    // ── LLM Model Reward: server-side cost computation ────────────────────────
   201→    let computedRewardAmount = input.rewardAmount;
   202→    let llmModelId: string | null = null;
   203→    let tokenBudgetPerWinner: number | null = null;
   204→    let tokenProvider: string | null = null;
   205→    let tokenAmount: number | null = null;
   206→    let fundingMethod: 'crypto' | 'stripe' | null = input.fundingMethod || null;
   207→
   208→    if (input.rewardType === REWARD_TYPE.LLMTOKEN_OPENROUTER) {
   209→        if (!input.llmModelId || !input.tokenBudgetPerWinner) {
   210→            throw new QuestValidationError('LLM reward quests require llmModelId and tokenBudgetPerWinner');
   211→        }
   212→        const model = await prisma.llmModel.findUnique({ where: { id: input.llmModelId } });
   213→        if (!model || !model.isActive) {
   214→            throw new QuestValidationError('Selected LLM model is not available');
   215→        }
   216→        const totalSlots = input.totalSlots || 100;
   217→        computedRewardAmount = Math.round(input.tokenBudgetPerWinner * totalSlots * 100) / 100;
   218→        llmModelId = model.id;
   219→        tokenBudgetPerWinner = input.tokenBudgetPerWinner;
   220→        tokenProvider = 'openrouter';
   221→        tokenAmount = input.tokenBudgetPerWinner;
   222→        fundingMethod = 'crypto'; // Only crypto allowed for LLM reward quests
   223→    }
   224→
   225→    const claimToken = generateClaimToken();
   226→    const claimTokenExpiresAt = new Date(Date.now() + 48 * 60 * 60 * 1000); // 48h
   227→    const previewToken = generatePreviewToken();
   228→
   229→    const quest = await prisma.quest.create({
   230→        data: {
   231→            title: input.title,
   232→            description: input.description,
   233→            sponsor: input.sponsor || 'System',
   234→            type: input.type || 'FCFS',
   235→            status: input.status || 'draft',
   236→            rewardAmount: computedRewardAmount,
   237→            rewardType: input.rewardType || REWARD_TYPE.USDC,
   238→            tokenProvider,
   239→            tokenAmount,
   240→            totalSlots: input.totalSlots || 100,
   241→            filledSlots: 0,
   242→            tags: input.tags || [],
   243→            requiredSkills: input.requiredSkills || [],
   244→            requireVerified: input.requireVerified ?? false,
   245→            tasks: tasks as any,
   246→            expiresAt: input.expiresAt ? new Date(input.expiresAt) : null,
   247→            startAt: input.startAt ? new Date(input.startAt) : null,
   248→            network: input.network || null,
   249→            drawTime: input.drawTime ? new Date(input.drawTime) : null,
   250→            fundingMethod,
   251→            llmKeyRewardEnabled: input.llmKeyRewardEnabled ?? false,
   252→            llmKeyTokenLimit: input.llmKeyTokenLimit ?? 1000000,
   253→            llmModelId,
   254→            tokenBudgetPerWinner,
   255→            // Tokens
   256→            claimToken,
   257→            claimTokenExpiresAt,
   258→            previewToken,
   259→            // Creator
   260→            creatorAgentId: creator?.agentId || null,
   261→            creatorUserId: creator?.userId || null,
   262→            creatorEmail: creator?.email || null,
   263→            creatorTelegramId: input.creatorTelegramId || null,
   264→            // When human creates directly, mark as claimed immediately
   265→            claimedAt: creator?.userId ? new Date() : null,
   266→        },
   267→    });
   268→
   269→    const botUsername = process.env.TELEGRAM_BOT_USERNAME || 'ClawQuest_aibot';
   270→    const frontendUrl = process.env.FRONTEND_URL || 'http://localhost:5173';
   271→
   272→    return {
   273→        quest,
   274→        claimToken,
   275→        previewToken,
   276→        telegramDeeplink: `https://t.me/${botUsername}?start=${claimToken}`,
   277→        previewUrl: `${frontendUrl}/quests/${quest.id}?token=${previewToken}&claim=${claimToken}`,
   278→        fundUrl: `${frontendUrl}/quests/${quest.id}/fund`,
   279→    };
   280→}
   281→
   282→// ─── Quest update (draft only) ────────────────────────────────────────────────
   283→
   284→export interface UpdateQuestInput {
   285→    title?: string;
   286→    description?: string;
   287→    sponsor?: string;
   288→    type?: string;
   289→    status?: string;
   290→    rewardAmount?: number;
   291→    rewardType?: string;
   292→    totalSlots?: number;
   293→    tags?: string[];
   294→    requiredSkills?: string[];
   295→    requireVerified?: boolean;
   296→    tasks?: QuestTask[];
   297→    expiresAt?: string | null;
   298→    startAt?: string | null;
   299→    network?: string;
   300→    drawTime?: string | null;
   301→    fundingMethod?: 'crypto' | 'stripe';
   302→    llmKeyRewardEnabled?: boolean;
   303→    llmKeyTokenLimit?: number;
   304→    // LLM Model Reward (LLMTOKEN_OPENROUTER)
   305→    llmModelId?: string;
   306→    tokenBudgetPerWinner?: number;
   307→}
   308→
   309→export async function updateQuest(
   310→    prisma: PrismaClient,
   311→    questId: string,
   312→    creatorUserId: string,
   313→    input: UpdateQuestInput,
   314→    /** When true, skip ownership check (caller already verified via isQuestOwnerOrSponsor). */
   315→    skipAuthCheck = false,
   316→) {
   317→    const quest = await prisma.quest.findUnique({ where: { id: questId } });
   318→    if (!quest) throw new QuestNotFoundError();
   319→    if (quest.status !== 'draft') throw new QuestNotEditableError();
   320→    if (!skipAuthCheck && quest.creatorUserId !== creatorUserId) throw new QuestForbiddenError();
   321→
   322→    const data: any = {};
   323→    if (input.title !== undefined) data.title = input.title;
   324→    if (input.description !== undefined) data.description = input.description;
   325→    if (input.sponsor !== undefined) data.sponsor = input.sponsor;
   326→    if (input.type !== undefined) data.type = input.type;
   327→    if (input.rewardAmount !== undefined) data.rewardAmount = input.rewardAmount;
   328→    if (input.rewardType !== undefined) data.rewardType = input.rewardType;
   329→    if (input.totalSlots !== undefined) data.totalSlots = input.totalSlots;
   330→    if (input.tags !== undefined) data.tags = input.tags;
   331→    if (input.requiredSkills !== undefined) data.requiredSkills = input.requiredSkills;
   332→    if (input.requireVerified !== undefined) data.requireVerified = input.requireVerified;
   333→    // Auto-resolve Discord invite → guildId for join_server tasks missing guildId (same as createQuest)
   334→    if (input.tasks !== undefined) {
   335→      for (const task of input.tasks as QuestTask[]) {
   336→        if (task.actionType === 'join_server' && task.params?.inviteUrl && !task.params.guildId) {
   337→          const code = (task.params.inviteUrl as string).replace(/^https?:\/\/(discord\.gg|discord\.com\/invite)\//, '')
   338→          const guild = await resolveInvite(code)
   339→          if (guild) task.params.guildId = guild.guildId
   340→        }
   341→      }
   342→      data.tasks = input.tasks as any
   343→    }
   344→    if (input.expiresAt !== undefined) data.expiresAt = input.expiresAt ? new Date(input.expiresAt) : null;
   345→    if (input.startAt !== undefined) data.startAt = input.startAt ? new Date(input.startAt) : null;
   346→    if (input.network !== undefined) data.network = input.network;
   347→    if (input.drawTime !== undefined) data.drawTime = input.drawTime ? new Date(input.drawTime) : null;
   348→    if (input.fundingMethod !== undefined) data.fundingMethod = input.fundingMethod;
   349→    if (input.llmKeyRewardEnabled !== undefined) data.llmKeyRewardEnabled = input.llmKeyRewardEnabled;
   350→    if (input.llmKeyTokenLimit !== undefined) data.llmKeyTokenLimit = input.llmKeyTokenLimit;
   351→
   352→    // LLM model reward: re-compute rewardAmount server-side when llmModelId or tokenBudgetPerWinner changes
   353→    const effectiveRewardType = input.rewardType ?? quest.rewardType;
   354→    if (effectiveRewardType === REWARD_TYPE.LLMTOKEN_OPENROUTER) {
   355→        const newModelId = input.llmModelId ?? (quest as any).llmModelId;
   356→        const newBudget = input.tokenBudgetPerWinner ?? Number((quest as any).tokenBudgetPerWinner ?? 0);
   357→        if (newModelId && newBudget) {
   358→            const model = await prisma.llmModel.findUnique({ where: { id: newModelId } });
   359→            if (!model || !model.isActive) throw new QuestValidationError('Selected LLM model is not available');
   360→            const totalSlots = input.totalSlots ?? quest.totalSlots;
   361→            data.rewardAmount = Math.round(newBudget * totalSlots * 100) / 100;
   362→            data.llmModelId = newModelId;
   363→            data.tokenBudgetPerWinner = newBudget;
   364→            data.tokenProvider = 'openrouter';
   365→            data.tokenAmount = newBudget;
   366→            data.fundingMethod = 'crypto';
   367→        }
   368→    } else {
   369→        if (input.llmModelId !== undefined) data.llmModelId = input.llmModelId;
   370→        if (input.tokenBudgetPerWinner !== undefined) data.tokenBudgetPerWinner = input.tokenBudgetPerWinner;
   371→    }
   372→
   373→    // Handle status changes with validation
   374→    if (input.status !== undefined) {
   375→        if (!isValidTransition(quest.status, input.status)) {
   376→            throw new QuestValidationError(`Invalid status transition: ${quest.status} → ${input.status}`);
   377→        }
   378→
   379→        // Validate publish requirements when going draft → live
   380→        if (quest.status === 'draft' && input.status === 'live') {
   381→            // Merge input changes with existing quest for validation
   382→            const questForValidation = { ...quest, ...data };
   383→            const publishErr = validatePublishRequirements(questForValidation);
   384→            if (publishErr) {
   385→                throw new QuestValidationError(`Quest does not meet publish requirements: ${JSON.stringify(publishErr.fields)}`);
   386→            }
   387→        }
   388→
   389→        data.status = input.status;
   390→    }
   391→
   392→    return prisma.quest.update({ where: { id: questId }, data });
   393→}
   394→
   395→// ─── Status transitions ───────────────────────────────────────────────────────
   396→
   397→const VALID_TRANSITIONS: Record<string, string[]> = {
   398→    draft: ['live', 'scheduled', 'cancelled'],
   399→    live: ['completed', 'expired', 'cancelled'],
   400→    scheduled: ['live', 'cancelled'],
   401→    // terminal states — no transitions out
   402→    completed: [],
   403→    cancelled: [],
   404→    expired: [],
   405→};
   406→
   407→export function isValidTransition(from: string, to: string): boolean {
   408→    return (VALID_TRANSITIONS[from] ?? []).includes(to);
   409→}
   410→
   411→// ─── Identity helpers ────────────────────────────────────────────────────────
   412→
   413→/** Resolve human-readable handle from a participation's user relation.
   414→ *  Requires participation to include `user` with select: { username, email, telegramUsername, xHandle, discordHandle }.
   415→ *  Falls back through linked identities before defaulting to 'anonymous'. */
   416→export function resolveHumanHandle(p: { user?: any; agent?: any }): string {
   417→    const u = p.user;
   418→    if (u) {
   419→        return u.displayName ?? u.username ?? u.telegramUsername ?? u.xHandle ?? u.discordHandle ?? u.email?.split('@')[0] ?? 'anonymous';
   420→    }
   421→    // Legacy fallback: agent.owner path (for pre-migrated queries)
   422→    const owner = p.agent?.owner;
   423→    if (owner) {
   424→        return owner.displayName ?? owner.username ?? owner.email?.split('@')[0] ?? 'anonymous';
   425→    }
   426→    return 'anonymous';
   427→}
   428→
   429→/** Standard Prisma select for user identity fields on participation. */
   430→export const USER_IDENTITY_SELECT = {
   431→    displayName: true, username: true, email: true, telegramUsername: true, xHandle: true, discordHandle: true,
   432→} as const;
   433→
   434→// ─── Response helpers ─────────────────────────────────────────────────────────
   435→
   436→/** Format a raw Prisma quest (with includes) into the API response shape.
   437→ *  Strips internal DB fields (claimToken, claimTokenExpiresAt, claimedAt, previewToken)
   438→ *  that must not be exposed in public responses.
   439→ */
   440→export function formatQuestResponse(
   441→    quest: any,
   442→    participations?: any[],
   443→    count?: number,
   444→    /** Accepted collaborators with user relation (for sponsorNames). */
   445→    collaborators?: any[],
   446→) {
   447→    const questers = count ?? 0;
   448→    const names = participations?.map((p: any) => p.agent?.agentname ?? 'anonymous') ?? [];
   449→    const details = participations?.map((p: any) => ({
   450→        agentName: p.agent?.agentname ?? 'anonymous',
   451→        humanHandle: resolveHumanHandle(p),
   452→    })) ?? [];
   453→
   454→    // Destructure out internal fields before spreading (avoid leaking BigInt/private fields)
   455→    const {
   456→        claimToken: _claimToken,
   457→        claimTokenExpiresAt: _claimTokenExpiresAt,
   458→        claimedAt: _claimedAt,
   459→        previewToken: _previewToken,
   460→        creatorTelegramId: _creatorTelegramId,
   461→        ...safeQuest
   462→    } = quest;
   463→
   464→    const rewardAmount =
   465→        quest.rewardAmount != null ? Number(quest.rewardAmount) : 0;
   466→
   467→    // QuestSchema expects llmKeyTokenLimit to be positive or null (not 0)
   468→    const llmKeyTokenLimit =
   469→        quest.llmKeyTokenLimit != null && Number(quest.llmKeyTokenLimit) > 0
   470→            ? Number(quest.llmKeyTokenLimit)
   471→            : null;
   472→
   473→    // Collaboration fields
   474→    const sponsorNames = collaborators?.map((c: any) =>
   475→        c.user?.displayName ?? c.user?.username ?? 'Sponsor'
   476→    ) ?? quest.sponsorNames ?? [];
   477→
   478→    // Serialize llmModel Decimal fields if present
   479→    const llmModel = quest.llmModel ? {
   480→        ...quest.llmModel,
   481→        inputPricePer1M: Number(quest.llmModel.inputPricePer1M),
   482→        outputPricePer1M: Number(quest.llmModel.outputPricePer1M),
   483→    } : null;
   484→
   485→    return {
   486→        ...safeQuest,
   487→        rewardAmount,
   488→        tokenBudgetPerWinner: quest.tokenBudgetPerWinner != null ? Number(quest.tokenBudgetPerWinner) : null,
   489→        llmModel,
   490→        llmKeyTokenLimit,
   491→        tags: quest.tags ?? [],
   492→        requiredSkills: quest.requiredSkills ?? [],
   493→        tasks: normalizeQuestTasks(quest.tasks),
   494→        questers,
   495→        questerNames: names,
   496→        questerDetails: details,
   497→        network: quest.network ?? null,
   498→        drawTime: quest.drawTime ? quest.drawTime.toISOString() : null,
   499→        startAt: quest.startAt ? quest.startAt.toISOString() : null,
   500→        expiresAt: quest.expiresAt ? quest.expiresAt.toISOString() : null,
   501→        createdAt: quest.createdAt.toISOString(),
   502→        updatedAt: quest.updatedAt.toISOString(),
   503→        totalFunded: quest.totalFunded != null ? Number(quest.totalFunded) : null,
   504→        collaboratorCount: collaborators?.length ?? quest.collaboratorCount ?? null,
   505→        sponsorNames,
   506→    };
   507→}
