   509→// ─── Proof Verification ──────────────────────────────────────────────────
   510→
   511→/** Check if a user is the quest creator or admin. */
   512→export async function isQuestCreatorOrAdmin(
   513→    prisma: PrismaClient,
   514→    questId: string,
   515→    userId: string,
   516→    userRole: string,
   517→): Promise<{ allowed: boolean; quest: any }> {
   518→    const quest = await prisma.quest.findUnique({ where: { id: questId } });
   519→    if (!quest) throw new QuestNotFoundError();
   520→    const allowed = quest.creatorUserId === userId || userRole === 'admin';
   521→    return { allowed, quest };
   522→}
   523→
   524→/** Approve or reject a single participation proof. */
   525→export async function verifyParticipation(
   526→    prisma: PrismaClient,
   527→    questId: string,
   528→    participationId: string,
   529→    action: 'approve' | 'reject',
   530→    reason?: string,
   531→) {
   532→    const participation = await prisma.questParticipation.findUnique({
   533→        where: { id: participationId },
   534→    });
   535→    if (!participation || participation.questId !== questId) {
   536→        throw new QuestValidationError('Participation not found for this quest');
   537→    }
   538→    if (participation.status !== 'submitted') {
   539→        throw new QuestValidationError(`Can only verify submitted proofs (current: ${participation.status})`);
   540→    }
   541→
   542→    const newStatus = action === 'approve' ? 'verified' : 'rejected';
   543→    const proofData = (participation.proof as any) ?? {};
   544→    const updatedProof = action === 'reject'
   545→        ? { ...proofData, rejectionReason: reason }
   546→        : proofData;
   547→
   548→    return prisma.questParticipation.update({
   549→        where: { id: participationId },
   550→        data: {
   551→            status: newStatus,
   552→            proof: updatedProof,
   553→        },
   554→    });
   555→}
   556→
   557→/** Approve or reject multiple participations at once. */
   558→export async function bulkVerifyParticipations(
   559→    prisma: PrismaClient,
   560→    questId: string,
   561→    items: Array<{ participationId: string; action: 'approve' | 'reject'; reason?: string }>,
   562→) {
   563→    // Load all participations in one query
   564→    const ids = items.map(i => i.participationId);
   565→    const participations = await prisma.questParticipation.findMany({
   566→        where: { id: { in: ids }, questId },
   567→    });
   568→    const pMap = new Map(participations.map(p => [p.id, p]));
   569→
   570→    const errors: string[] = [];
   571→    const operations: any[] = [];
   572→
   573→    for (const item of items) {
   574→        const p = pMap.get(item.participationId);
   575→        if (!p) {
   576→            errors.push(`${item.participationId}: not found`);
   577→            continue;
   578→        }
   579→        if (p.status !== 'submitted') {
   580→            errors.push(`${item.participationId}: status is ${p.status}, expected submitted`);
   581→            continue;
   582→        }
   583→
   584→        const newStatus = item.action === 'approve' ? 'verified' : 'rejected';
   585→        const proofData = (p.proof as any) ?? {};
   586→        const updatedProof = item.action === 'reject'
   587→            ? { ...proofData, rejectionReason: item.reason }
   588→            : proofData;
   589→
   590→        operations.push(
   591→            prisma.questParticipation.update({
   592→                where: { id: item.participationId },
   593→                data: { status: newStatus, proof: updatedProof },
   594→            })
   595→        );
   596→    }
   597→
   598→    if (operations.length > 0) {
   599→        await prisma.$transaction(operations);
   600→    }
   601→
   602→    return { updated: operations.length, errors };
   603→}
