                                            )}
                                        </div>
                                    )}
                                </div>
                            )}

                        {/* ── LLM API Key Reward ── */}
                        {isAuthenticated && quest.myParticipation?.llmRewardApiKey && (
                            <LlmKeyCard apiKey={quest.myParticipation.llmRewardApiKey} />
